const raw = $input.first().json.content[0].text.trim();
let parsed;
try {
  const cleaned = raw.replace(/^```json\s*/i, '').replace(/```\s*$/i, '').trim();
  parsed = JSON.parse(cleaned);
} catch(e) {
  parsed = { sms_text: "Hi! We'd love to help you find the right vehicle. When's a good time to connect?", intent_score: 'cold', intent_reasoning: 'fallback — could not parse Claude response' };
}
const ctx = $('Build Prompt1').first().json._ctx;
const step = ctx.sequence_step || 0;
const days = [3, 4, 7, 16, null];
const nextDays = days[step] ?? null;
const nextFollowUp = nextDays ? new Date(Date.now() + nextDays * 86400000).toISOString() : null;

let newStage;
if (parsed.intent_score === 'hot') newStage = 'hot';
else if (parsed.intent_score === 'warm') newStage = 'warm';
else if (step === 0) newStage = 'needs_reply';
else newStage = 'contacted';
if (step >= 4 && !nextFollowUp) newStage = 'closed';

return [{ json: {
  lead_id: ctx.lead_id,
  trigger_type: ctx.trigger_type,
  demo_mode: ctx.demo_mode,
  phone: ctx.phone,
  sms_text: parsed.sms_text,
  intent_score: parsed.intent_score || 'cold',
  intent_reasoning: parsed.intent_reasoning || '',
  new_stage: newStage,
  next_follow_up: nextFollowUp,
  next_step: step + 1,
  sms_count: (ctx.sms_count || 0) + 1,
  is_hot: parsed.intent_score === 'hot',
  salesperson_alerted: ctx.salesperson_alerted,
  now: new Date().toISOString(),
} }];

// Demo mode: prepend [DEMO] and skip Twilio
const data = $('Parse & Enrich1').first().json;
return [{ json: { ...data, sms_text: '[DEMO] ' + data.sms_text } }];

